    public function getSourceContext(): Source
    {
        return new Source("{% use \x27form_div_layout.html.twig\x27 %}

{%- block form_row -%}
    {%- set row_attr = row_attr|merge({class: row_attr.class|default(row_class|default(\x27flex flex-col mb-6\x27))}) -%}
    {{- parent() -}}
{%- endblock form_row -%}

{%- block widget_attributes -%}
    {%- set widget_errors_class = widget_errors_class is defined ? widget_errors_class : \x27input-error\x27 -%}
    {%- set attr = attr|merge({class: attr.class|default(widget_class|default(\x27mt-1 w-full\x27)) ~ (errors|length and widget_errors_class ? \x27 \x27 ~ widget_errors_class : \x27\x27)}) -%}
    {{- parent() -}}
{%- endblock widget_attributes -%}

{%- block form_errors -%}
    {%- if errors|length > 0 -%}
        <ul>
            {%- for error in errors -%}
                <li class=\"{{ error_item_class|default(\x27text-error\x27) }}\" id=\"{{ id ~ \x27_error\x27 ~ loop.index }}\">{{ error.message }}</li>
            {%- endfor -%}
        </ul>
    {%- endif -%}
{%- endblock form_errors -%}

{%- block form_help -%}
    {%- set help_attr = help_attr|merge({class: (help_attr.class|default(\x27mt-1 label\x27))|trim}) -%}
    {{- parent() -}}
{%- endblock form_help -%}

{%- block form_label -%}
    {%- set label_attr = label_attr|merge({class: label_attr.class|default(label_class|default(\x27label\x27))}) -%}
    {{- parent() -}}
{%- endblock form_label -%}

{%- block button_widget -%}
    {%- set attr = attr|merge({class: (attr.class|default(\x27btn-neutral\x27) ~ \x27 btn\x27)|trim}) -%}
    {{- parent() -}}
{%- endblock button_widget %}

{%- block submit_widget -%}
    {%- set attr = attr|merge({class: (attr.class|default(\x27btn-primary\x27))|trim}) -%}
    {{- parent() -}}
{%- endblock submit_widget %}

{%- block choice_widget_expanded -%}
    {%- set attr = attr|merge({class: attr.class|default(\x27mt-2\x27)}) -%}
    <div {{ block(\x27widget_container_attributes\x27) }}>
        {%- for child in form %}
            <label class=\"flex items-center label mb-2\">
                {{- form_widget(child) -}}
                {%- if child.vars.label is not same as(false) -%}
                    {{- form_label(child, null, {translation_domain: choice_translation_domain, label_attr: {class: \x27\x27}}) -}}
                {%- endif -%}
            </label>
        {% endfor -%}
    </div>
{%- endblock choice_widget_expanded -%}

{%- block checkbox_row -%}
    {%- set row_attr = row_attr|merge({class: row_attr.class|default(row_class|default(\x27mb-6\x27))}) -%}
    {%- set widget_attr = {} -%}
    {%- if help is not empty -%}
        {%- set widget_attr = {attr: {\x27aria-describedby\x27: id ~ \x27_help\x27}} -%}
    {%- endif -%}
    <div{% with {attr: row_attr} %}{{ block(\x27attributes\x27) }}{% endwith %}>
        {{- form_errors(form) -}}
        <label class=\"flex items-center label mb-2\">
            {{- form_widget(form, widget_attr) -}}
            {{- block(\x27form_label_content\x27) -}}
        </label>
        {{- form_help(form) -}}
    </div>
{%- endblock checkbox_row -%}

{%- block checkbox_widget -%}
    {%- set widget_class = (widget_class|default(\x27checkbox\x27) ~ (errors|length ? \x27 checkbox-error\x27)) -%}
    {{- parent() -}}
{%- endblock checkbox_widget -%}

{% block radio_widget -%}
{%- set widget_class = (widget_class|default(\x27radio\x27) ~ (errors|length ? \x27 radio-error\x27)) -%}
    {{- parent() -}}
{%- endblock radio_widget %}

{%- block choice_widget_collapsed -%}
    {%- set attr = attr|merge({class: (attr.class|default(\x27\x27) ~ \x27 select mt-2\x27)|trim}) -%}
    {{- parent() -}}
{%- endblock choice_widget_collapsed -%}

{% block textarea_widget -%}
    {% set attr = attr|merge({class: (attr.class|default(\x27\x27) ~ \x27 textarea mt-2\x27)|trim}) %}
    {{- parent() -}}
{%- endblock textarea_widget %}

{%- block range_widget -%}
    {% set type = type|default(\x27range\x27) %}
    {%- set widget_class = widget_class|default(\x27range mt-2\x27) -%}
    {{- block(\x27form_widget_simple\x27) -}}
{%- endblock range_widget %}

{%- block file_widget -%}
    {% set type = type|default(\x27file\x27) %}
    {%- set widget_class = widget_class|default(\x27file-input mt-2\x27) -%}
    {%- set widget_errors_class = \x27file-input-error\x27 -%}
    {{- block(\x27form_widget_simple\x27) -}}
{%- endblock file_widget %}

{% block form_widget_simple -%}
    {%- if type is not defined or type not in [\x27hidden\x27, \x27range\x27, \x27file\x27] %}
        {%- set widget_class = widget_class|default(\x27input mt-2\x27) -%}
    {% endif -%}

    {{- parent() -}}
{%- endblock form_widget_simple %}
